/**
 * Handle mode-switching intents. Returns true if consumed.
 */
// @kern-source: dispatch:234
export function handleModeSwitch(intentType: string, topic: string|undefined, question: string|undefined, cb: DispatchCallbacks): boolean {
  if (intentType === 'campfire' && !topic) {
    cb.setMode('campfire');
    cb.dispatch({ type: 'success', message: 'Switched to campfire mode — just talk, all engines think together' });
    return true;
  }
  if (intentType === 'brainstorm' && !question) {
    cb.setMode('brainstorm');
    cb.dispatch({ type: 'success', message: 'Switched to brainstorm mode — engines bid on your questions' });
    return true;
  }
  if (intentType === 'tribunal' && !question) {
    cb.setMode('tribunal');
    cb.dispatch({ type: 'success', message: 'Switched to tribunal mode — engines debate your questions' });
    return true;
  }
  if (intentType === 'chat') {
    if (cb.mode !== 'chat') {
      cb.setMode('chat');
      cb.dispatch({ type: 'success', message: 'Switched to chat mode' });
    }
    return false; // May have input to process
  }
  return false;
}

/**
 * Extract a fitness command from conversational execution input while keeping the task clean.
 */
// @kern-source: dispatch:262
export function extractExecutionSpec(input: string): { task:string; fitnessCmd:string|null } {
  const fitnessMatch = FITNESS_PATTERN.exec(input);
  const fitnessCmd = fitnessMatch ? fitnessMatch[1].trim() : null;
  const task = fitnessCmd
    ? input.replace(FITNESS_PATTERN, '').trim()
    : input.trim();
  return { task, fitnessCmd };
}

/**
 * Compact user-facing Cesar recovery messages. Keep these short because they render in the live status/transcript path during failure handling.
 */
// @kern-source: dispatch:273
export function formatCesarRecoveryStatus(stage: 'delegation'|'rebuild'|'retry'|'acting'|'failed', subject: string, detail?: string): string {
  const suffix = detail ? ` - ${detail}` : '';
  switch (stage) {
    case 'delegation':
      return `Cesar recovery: running ${subject}${suffix}`;
    case 'rebuild':
      return `Cesar recovery: rebuilding ${subject} session${suffix}`;
    case 'retry':
      return `Cesar recovery: retrying ${subject} with fresh dispatch${suffix}`;
    case 'acting':
      return `Cesar recovery: ${subject} acting as Cesar${suffix}`;
    case 'failed':
      return `Cesar recovery failed: ${subject}${suffix}`;
    default:
      return `Cesar recovery: ${subject}${suffix}`;
  }
}

